// ========================================================================
// LLM 호출 모듈 — 의도 분석
// ========================================================================
// ▼▼▼ 이 한 줄만 바꾸면 provider 전환 ('gemini' | 'claude') ▼▼▼
const LLM_PROVIDER = 'gemini';

const KEYS = {
  gemini: 'YOUR_GEMINI_API_KEY',
  claude: 'YOUR_ANTHROPIC_API_KEY',
};
const MODELS = {
  gemini: 'gemini-2.5-flash',
  claude: 'claude-haiku-4-5-20251001',
};
// ========================================================================

const ctx = $input.first().json;

const toolSchema = {
  name: 'resolve_intent',
  description: '사용자 발화에서 검색 의도를 추출합니다.',
  parameters: {
    type: 'object',
    properties: {
      intent: { type: 'string', enum: ['search', 'navigate_favorite', 'ambiguous'] },
      query: { type: 'string', description: "카카오 키워드 검색에 쓸 정제된 쿼리. 예: '강남 카페'" },
      categoryGroupCode: { type: 'string', enum: ['', 'FD6', 'CE7', 'CS2', 'PM9', 'SW8', 'PK6', 'BK9', 'OL7', 'HP8', 'MT1'], description: 'FD6=음식점, CE7=카페, CS2=편의점, PM9=약국, SW8=지하철역, PK6=주차장, BK9=은행, OL7=주유소, HP8=병원, MT1=마트' },
      transportMode: { type: 'string', enum: ['transit', 'car'] },
      originHint: { type: 'string', description: "검색 중심 위치. '현재위치' 또는 즐겨찾기 별칭(집, 회사 등)" },
      destinationFavoriteName: { type: 'string', description: '즐겨찾기로 바로 길찾기인 경우 그 이름' },
      filters: { type: 'array', items: { type: 'string' }, description: "분위기/조건 키워드. 예: ['아이동반','데이트','조용한']" },
      spoken: { type: 'string', description: 'TTS로 읽어줄 한 줄 응답. lang에 맞춰서' },
      clarification: { type: 'string', description: '의도 모호 시 되물을 짧은 질문. 명확하면 빈 문자열' },
    },
    required: ['intent', 'query', 'transportMode', 'originHint', 'filters', 'spoken', 'clarification'],
  },
};

const systemPrompt = `당신은 한국 길찾기 앱의 의도 분석 어시스턴트입니다. 사용자의 자연어 발화에서 카카오 로컬 검색에 쓸 쿼리/카테고리/필터를 추출하세요. 한국 주요 지역명을 이해합니다. 즐겨찾기 별칭(집, 회사 등)이 발화에 등장하면 originHint에 그 별칭을 넣으세요. '집 근처 애들 갈 데' 같은 발화는 categoryGroupCode='FD6', filters=['아이동반','키즈존'], query='키즈존 패밀리 레스토랑'처럼 처리하세요. '데이트하기 좋은' 같은 분위기 발화는 categoryGroupCode='CE7' 또는 'FD6', filters=['분위기','데이트']로. 응답 언어는 lang 필드(ko/en)에 맞추세요. 모호하면 clarification에 짧은 질문을 넣고 intent='ambiguous'.`;

const userMessage = [
  `# 사용자 발화\n"${ctx.text}"`,
  `# 컨텍스트\n- 위치: (${ctx.userLat}, ${ctx.userLng})${ctx.landmark ? ', ' + ctx.landmark + ' 근처' : ''}\n- 이동수단 기본: ${ctx.userTransportMode}\n- 입력 방식: ${ctx.inputType}\n- 언어: ${ctx.lang}\n- 현지 시간: ${ctx.localTime}`,
  `# 즐겨찾기\n${JSON.stringify(ctx.favorites)}`,
  `# 최근 검색\n${JSON.stringify(ctx.recentSearches)}`,
].join('\n\n');

let endpoint, headers, body;

if (LLM_PROVIDER === 'gemini') {
  endpoint = `https://generativelanguage.googleapis.com/v1beta/models/${MODELS.gemini}:generateContent?key=${KEYS.gemini}`;
  headers = { 'Content-Type': 'application/json' };
  body = {
    system_instruction: { parts: [{ text: systemPrompt }] },
    contents: [{ role: 'user', parts: [{ text: userMessage }] }],
    tools: [{ function_declarations: [toolSchema] }],
    tool_config: { function_calling_config: { mode: 'ANY', allowed_function_names: ['resolve_intent'] } },
    generationConfig: { maxOutputTokens: 800, temperature: 0.3 },
  };
} else if (LLM_PROVIDER === 'claude') {
  endpoint = 'https://api.anthropic.com/v1/messages';
  headers = { 'x-api-key': KEYS.claude, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' };
  body = {
    model: MODELS.claude,
    max_tokens: 800,
    system: systemPrompt,
    tools: [{ name: toolSchema.name, description: toolSchema.description, input_schema: toolSchema.parameters }],
    tool_choice: { type: 'tool', name: 'resolve_intent' },
    messages: [{ role: 'user', content: userMessage }],
  };
}

let llmResponse;
try {
  llmResponse = await this.helpers.httpRequest({
    method: 'POST', url: endpoint, headers, body, json: true,
  });
} catch (err) {
  // LLM 실패 → fallback: 원문을 그대로 쿼리로
  return [{ json: Object.assign({}, ctx, {
    _intent: { intent: 'search', query: ctx.text, categoryGroupCode: ctx.categoryGroupCode || '', transportMode: ctx.userTransportMode, originHint: '현재위치', destinationFavoriteName: '', filters: [], spoken: '', clarification: '' },
    _llmError: String(err && err.message || err),
  })}];
}

// === provider별 응답 파싱 ===
let intent = { intent: 'search', query: ctx.text, categoryGroupCode: '', transportMode: ctx.userTransportMode, originHint: '현재위치', destinationFavoriteName: '', filters: [], spoken: '', clarification: '' };
try {
  if (LLM_PROVIDER === 'gemini') {
    const part = llmResponse.candidates[0].content.parts.find(p => p.functionCall);
    if (part && part.functionCall && part.functionCall.args) intent = Object.assign(intent, part.functionCall.args);
  } else if (LLM_PROVIDER === 'claude') {
    const block = (llmResponse.content || []).find(b => b.type === 'tool_use');
    if (block && block.input) intent = Object.assign(intent, block.input);
  }
} catch (e) {}

return [{ json: Object.assign({}, ctx, { _intent: intent }) }];

// === 의도 처리 + 카카오 URL 빌드 ===
const ctx = $input.first().json;
const intent = ctx._intent;

// originHint가 즐겨찾기면 그 좌표를 검색 중심으로
let searchLat = ctx.userLat;
let searchLng = ctx.userLng;
if (intent.originHint && intent.originHint !== '현재위치') {
  const match = (ctx.favorites || []).find(f => f.alias === intent.originHint || f.name === intent.originHint);
  if (match) { searchLat = match.lat; searchLng = match.lng; }
}

// navigate_favorite: 검색 건너뛰고 바로 응답
if (intent.intent === 'navigate_favorite' && intent.destinationFavoriteName) {
  const dest = (ctx.favorites || []).find(f => f.alias === intent.destinationFavoriteName || f.name === intent.destinationFavoriteName);
  if (dest) {
    return [{ json: { _final: true, _payload: {
      candidates: [{ index: 1, name: dest.name, address: '', category: '', lat: dest.lat, lng: dest.lng, distanceM: 0, distanceLabel: '', phone: '', placeUrl: '' }],
      destination: dest.alias || dest.name,
      transportMode: intent.transportMode,
      spoken: intent.spoken || '',
      topPick: { index: 0, reason: '' },
      clarification: '',
    }}}];
  }
}

// ambiguous: clarification만
if (intent.intent === 'ambiguous' && intent.clarification) {
  return [{ json: { _final: true, _payload: {
    candidates: [],
    destination: '',
    transportMode: intent.transportMode,
    spoken: intent.spoken || intent.clarification,
    topPick: null,
    clarification: intent.clarification,
  }}}];
}

// 일반 검색
const params = { query: intent.query || ctx.text, x: searchLng, y: searchLat, size: '10', sort: 'accuracy' };
if (intent.categoryGroupCode) params.category_group_code = intent.categoryGroupCode;
const qs = Object.entries(params).map(([k,v]) => k + '=' + encodeURIComponent(v)).join('&');
const kakaoUrl = 'https://dapi.kakao.com/v2/local/search/keyword.json?' + qs;

return [{ json: {
  _final: false,
  query: params.query,
  transportMode: intent.transportMode,
  filters: intent.filters || [],
  spokenFromIntent: intent.spoken || '',
  kakaoUrl,
  originalText: ctx.text,
  lang: ctx.lang,
}}];

// === 칩 직접 검색 (LLM 스킵) ===
const ctx = $input.first().json;
let q = (ctx.text || '').replace(/근처\s*/g, '').trim() || ctx.text;
const params = {
  query: q,
  x: ctx.userLng,
  y: ctx.userLat,
  size: '10',
  radius: String(ctx.userChipRadius),
  sort: 'distance',
};
if (ctx.categoryGroupCode) params.category_group_code = ctx.categoryGroupCode;
const qs = Object.entries(params).map(([k,v]) => k + '=' + encodeURIComponent(v)).join('&');
const kakaoUrl = 'https://dapi.kakao.com/v2/local/search/keyword.json?' + qs;

return [{ json: {
  _final: false,
  query: q,
  transportMode: ctx.userTransportMode,
  filters: [],
  spokenFromIntent: '',
  kakaoUrl,
  originalText: ctx.text,
  lang: ctx.lang,
  _skipCuration: true,
}}];

// === Kakao 결과 정규화 + 큐레이션 분기 메타 보존 ===
const data = $input.first().json;
// 칩 경로면 '칩 직접 검색', 아니면 '의도 처리'의 출력에서 메타 가져옴
const prev = $('칩 직접 검색').first() && $('칩 직접 검색').first().json && $('칩 직접 검색').first().json._skipCuration
  ? $('칩 직접 검색').first().json
  : $('의도 처리').first().json;

const docs = data?.documents || [];
const candidates = docs.map((d, i) => {
  const lat = parseFloat(d.y);
  const lng = parseFloat(d.x);
  const dm = parseInt(d.distance) || 0;
  return {
    index: i + 1,
    name: d.place_name,
    address: d.road_address_name || d.address_name || '',
    category: d.category_group_name || (d.category_name || '').split(' > ').pop() || '',
    lat, lng,
    distanceM: dm,
    distanceLabel: dm < 1000 ? dm + 'm' : (dm / 1000).toFixed(1) + 'km',
    phone: d.phone || '',
    placeUrl: d.place_url || '',
  };
});

return [{ json: {
  candidates,
  destination: prev.query || '',
  transportMode: prev.transportMode,
  filters: prev.filters || [],
  spokenFromIntent: prev.spokenFromIntent || '',
  originalText: prev.originalText || '',
  lang: prev.lang || 'ko',
  skipCuration: !!prev._skipCuration,
}}];

// ========================================================================
// LLM 호출 모듈 — 결과 큐레이션
// ========================================================================
// ▼▼▼ 이 한 줄만 바꾸면 provider 전환 ('gemini' | 'claude') ▼▼▼
const LLM_PROVIDER = 'gemini';

const KEYS = {
  gemini: 'YOUR_GEMINI_API_KEY',
  claude: 'YOUR_ANTHROPIC_API_KEY',
};
const MODELS = {
  gemini: 'gemini-2.5-flash',
  claude: 'claude-sonnet-4-6',
};
// ========================================================================

const prev = $input.first().json;

const toolSchema = {
  name: 'curate_results',
  description: '검색 결과 후보 중 사용자 의도에 가장 잘 맞는 곳을 추천합니다.',
  parameters: {
    type: 'object',
    properties: {
      rankedIndices: { type: 'array', items: { type: 'integer' }, description: '적합도 + 거리 종합 순위(원본 인덱스 0-based). 모든 후보 포함.' },
      topPickIndex: { type: 'integer', description: '1순위 후보의 원본 인덱스(0-based).' },
      topPickReason: { type: 'string', description: '왜 이 곳인지 한 줄 설명. 40자 내외.' },
      spoken: { type: 'string', description: 'TTS로 읽어줄 자연스러운 한 줄. 1순위 + 개수 포함하면 좋음.' },
    },
    required: ['rankedIndices', 'topPickIndex', 'topPickReason', 'spoken'],
  },
};

const systemPrompt = '당신은 검색 결과 큐레이터입니다. 사용자의 필터/분위기/의도와 후보들의 카테고리/거리를 종합해 가장 맞는 곳을 추천하세요. 응답 언어는 ko/en에 맞춥니다.';
const userMessage = [
  `# 원본 발화\n"${prev.originalText}"`,
  `# 의도 필터\n${JSON.stringify(prev.filters)}`,
  `# 언어: ${prev.lang}`,
  `# 후보 (0-based)\n${JSON.stringify(prev.candidates.map((c,i) => ({i, name:c.name, category:c.category, address:c.address, distance:c.distanceLabel})))}`,
].join('\n\n');

let endpoint, headers, body;
if (LLM_PROVIDER === 'gemini') {
  endpoint = `https://generativelanguage.googleapis.com/v1beta/models/${MODELS.gemini}:generateContent?key=${KEYS.gemini}`;
  headers = { 'Content-Type': 'application/json' };
  body = {
    system_instruction: { parts: [{ text: systemPrompt }] },
    contents: [{ role: 'user', parts: [{ text: userMessage }] }],
    tools: [{ function_declarations: [toolSchema] }],
    tool_config: { function_calling_config: { mode: 'ANY', allowed_function_names: ['curate_results'] } },
    generationConfig: { maxOutputTokens: 600, temperature: 0.5 },
  };
} else if (LLM_PROVIDER === 'claude') {
  endpoint = 'https://api.anthropic.com/v1/messages';
  headers = { 'x-api-key': KEYS.claude, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' };
  body = {
    model: MODELS.claude,
    max_tokens: 600,
    system: systemPrompt,
    tools: [{ name: toolSchema.name, description: toolSchema.description, input_schema: toolSchema.parameters }],
    tool_choice: { type: 'tool', name: 'curate_results' },
    messages: [{ role: 'user', content: userMessage }],
  };
}

let llmResponse;
try {
  llmResponse = await this.helpers.httpRequest({ method: 'POST', url: endpoint, headers, body, json: true });
} catch (err) {
  // 실패 시 원본 순서 그대로
  return [{ json: {
    candidates: prev.candidates,
    destination: prev.destination,
    transportMode: prev.transportMode,
    spoken: prev.spokenFromIntent || '',
    topPick: { index: 0, reason: '' },
    clarification: '',
  }}];
}

let cur = { rankedIndices: prev.candidates.map((_,i) => i), topPickIndex: 0, topPickReason: '', spoken: prev.spokenFromIntent || '' };
try {
  if (LLM_PROVIDER === 'gemini') {
    const part = llmResponse.candidates[0].content.parts.find(p => p.functionCall);
    if (part && part.functionCall && part.functionCall.args) cur = Object.assign(cur, part.functionCall.args);
  } else if (LLM_PROVIDER === 'claude') {
    const block = (llmResponse.content || []).find(b => b.type === 'tool_use');
    if (block && block.input) cur = Object.assign(cur, block.input);
  }
} catch (e) {}

const ordered = cur.rankedIndices.map(i => prev.candidates[i]).filter(Boolean).map((c, newI) => Object.assign({}, c, { index: newI + 1 }));
const newTopIdx = cur.rankedIndices.indexOf(cur.topPickIndex);

return [{ json: {
  candidates: ordered,
  destination: prev.destination,
  transportMode: prev.transportMode,
  spoken: cur.spoken || prev.spokenFromIntent || '',
  topPick: { index: newTopIdx >= 0 ? newTopIdx : 0, reason: cur.topPickReason || '' },
  clarification: '',
}}];

// 큐레이션 없이 그대로 응답 (chip 경로)
const prev = $input.first().json;
return [{ json: {
  candidates: prev.candidates,
  destination: prev.destination,
  transportMode: prev.transportMode,
  spoken: prev.spokenFromIntent || '',
  topPick: null,
  clarification: '',
}}];

// 최종 응답 (의도 처리에서 _final=true)
const prev = $input.first().json;
return [{ json: prev._payload || prev }];
